var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くっ……！！","ENG":"Kgh...!!","TWN":"咳……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"설마, 그동안 뒤에서 우리를 베껴대고 있을 줄이야……!","JPN":"まさか、裏でずっとあたしたちをコピーしていたなんて……！","ENG":"I didn't realize you were copying us behind our backs all this time...!","TWN":"沒想到，這段時間你竟然在背後模仿我們……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대가 소란스럽군요.","JPN":"舞台が騒がしいですね。","ENG":"The stage is full of too much commotion.","TWN":"舞台真是熱鬧啊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"게임이 끝난 순간부터 모든 것은 예정된 전개예요.","JPN":"ゲームが終わった瞬間から、すべては予定通りの展開です。","ENG":"Everything after the Game's ending had already been planned.","TWN":"從遊戲結束的那一刻起，一切都是事先安排好的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"순순히 포기하세요. 당신은 이미 제 각본에서 벗어날 수 없습니다.","JPN":"大人しく諦めなさい。あなたはもう、私の脚本から逃げられません。","ENG":"So, give up. You cannot escape my script already.","TWN":"乖乖放棄吧，你已經無法逃出我的劇本了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크하아아악……!!","JPN":"ぐあああ……っ！！","ENG":"Graah!!","TWN":"嗚啊啊啊……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 치명상이로군요. 복부 출혈을 멈추지 못하면 죽을 겁니다.","JPN":"致命傷ですね。腹部の出血を止めないと死にますよ。","ENG":"With this, you are fatally wounded. If you don't stop the bleeding from your abdomen, you will die.","TWN":"這下是致命傷了，如果不能止住腹部出血的話，會死的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"크, 크큭……!","JPN":"く、くく……！","ENG":"K-keke...!","TWN":"呵，呵呵……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래, 어쩐지 익숙하다 했는데…….","JPN":"ああ、どうりで既視感がすると思った……","ENG":"Yeah, it felt somehow familiar...","TWN":"是啊，難怪覺得這麼熟悉……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뭐가 그리 우습죠?","JPN":"なにがおかしいんですか？","ENG":"What's so amusing?","TWN":"有什麼好笑的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"널 처음 봤을 때부터, 느껴졌던 이 불쾌한 느낌…….","JPN":"あんたを初めて見た瞬間から感じたこの不快感……","ENG":"This unpleasant feeling I've had since I first saw you...","TWN":"從第一次見到你開始，就覺得哪裡不對勁……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이제야 알겠어……. 지금까지 전면에 나서지 않았던 이유가 있었어…….","JPN":"やっとわかった……今まで前面に立つのをさけた理由……","ENG":"I get it now... Why you wouldn't show your face in the front lines...","TWN":"現在才明白……你一直沒有出手的原因……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너, 그 빌어먹을 <color=#ffd34c>암군</color>이랑 계약했구나?","JPN":"あんた、あのくそみたいな<color=#ffd34c>暗君</color>と契約したでしょ？","ENG":"You made a contract with that damned <color=#ffd34c>Ignorant Monarch</color>, didn't you?","TWN":"你和那個該死的<color=#ffd34c>昏君</color>簽了契約嗎！？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"의외네요. 그 힘은 아직 숨겨두고 있었는데.","JPN":"気づくとは驚きました。その力はまだ隠していたつもりなのに。","ENG":"That's surprising. I've been hiding that power from everyone.","TWN":"真意外，那股力量還一直隱藏著呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인정하죠. 역시 리트리버답게 제법 냄새를 잘 맡는군요.","JPN":"認めます。レトリーバーだけに、匂いに敏感なのですね。","ENG":"I'll admit. You do have a sharp nose like a real retriever.","TWN":"我承認。不愧是獵犬，嗅覺還真是靈敏。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼 네 목적은 역시 관 뚜껑을 여는 건가……?","JPN":"じゃあやっぱりあんたの目的は棺を開けること……？","ENG":"Then, your goal is to open the Coffin...?","TWN":"那麼，你的目的果然是打開棺材嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하지만 대체 무슨 배짱으로…….","JPN":"けど、なんの魂胆があって……","ENG":"But you'd have to be insane to–","TWN":"可是到底憑什麼……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 그걸 알아냈다고 해서 뭐가 달라질까요?","JPN":"さあ、それがわかったところで何も変わらないでしょう。","ENG":"Well, what changes with your knowing that?","TWN":"這個嘛，知道了又能有什麼不同呢？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아쉽지만, 그 정보가 제때 대장님께 도착하는 일은 없을 겁니다.","JPN":"残念ながら、その情報を隊長に伝えようとしたところで間に合いません。","ENG":"I'm sorry, but that information will never reach Commander's ears on time.","TWN":"可惜，這個資訊是不會被及時送到隊長手中的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 당신은 한동안 이 무대에서 퇴장하게 될 테니까.","JPN":"なぜなら、あなたにはしばらくこの舞台から退場してもらうので。","ENG":"That's because you will be off this stage for a while now.","TWN":"因為你將暫時退出這個舞台。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"쳇, 순순히 당해줄 것 같아?","JPN":"ちっ、大人しくやられるわけないでしょ！","ENG":"Tch! You think I'm going down that easily?","TWN":"嘖，你以為我會乖乖認命嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"마지막의 마지막까지 깽판 쳐줄 테니까…….","JPN":"力尽きるまで大暴れしてやるから……","ENG":"I'll make sure to cause a ruckus until the very end...","TWN":"我會糾纏到最後一刻……"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어디 끌어낼 수 있으면 끌어내 보라고!!","JPN":"やれるもんならやってみな！！","ENG":"so I dare you to end me if you can!!","TWN":"有本事就在這裡殺了我！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마지막 일격을 가하는 뉘앙스를 보이면서, 발밑 지면을 노려 도망칠 틈을 만들었군요.","JPN":"最後の一撃に見せかけて、足元を狙い逃げる隙を作ろうとしましたね。","ENG":"While pretending to attempt a final blow, she aimed at the ground, creating a chance to escape.","TWN":"看似要搏命一擊，但卻瞄準腳下的地面製造了逃跑的機會。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"얼핏 난폭해 보이지만, 의외로 치밀한 퍼스트윙다운 대처라고 할까요.","JPN":"一見粗雑にみせて意外と緻密なファーストウイングらしい対処です。","ENG":"It might seem violent at first glance, but one could say it was meticulous and a Firstwing-like behavior.","TWN":"乍看很粗暴，但實則心細呢，真不愧是弗斯特薇。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것은 각본대로. 그 정도는 예측했답니다.","JPN":"ですが、すべては脚本どおり。そのぐらいはすでに予測済みです。","ENG":"But everything is according to the script. I anticipated this much.","TWN":"但是一切都將按照劇本進行。這點我早就預料到了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 무대에서 퇴장하는 건, 결국 시간문제예요.","JPN":"あなたが舞台から退場するのは、時間の問題なのです。","ENG":"It's only a matter of time before you leave the stage.","TWN":"你從舞台上退場，終究只是時間問題。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀하세요, 리하르트 베르너.","JPN":"どうぞ、リヒャルト・ベルナー。","ENG":"Speak, Richard Werner.","TWN":"請說，理查·韋爾納。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"스완, 어떻게 됐지?","JPN":"スワン、どうなった？","ENG":"Swan, how did it turn out?","TWN":"史旺，怎麼回事？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L1_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"작전 구역에서 정체불명의 섬광을 목격했다는 보고가 들어왔는데.","JPN":"作戦区域から謎の閃光が目撃されたという報告が入った。","ENG":"There has been a report about observing an unidentified flash of light in the operational area.","TWN":"作戰區域內有報告稱目擊到了不明閃光。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"퍼스트윙에게 치명상을 입혔어요. 놓치긴 했지만, 아직 얼마 가지 못했을 겁니다.","JPN":"ファーストウイングに致命傷を負わせました。逃げられましたけど、そう遠くまでは行っていないはずです。","ENG":"Firstwing is severely injured. I lost her, but she couldn't have gone far.","TWN":"給弗斯特薇造成了致命傷。雖然讓她逃脫了，但應該跑不遠。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"좋아. 작전 구역 밖에서 대기하고 있던 수색대원들을 전부 투입시키겠다.","JPN":"よし。作戦区域の外で待機していた捜索隊員を全員進入させる。","ENG":"All right. I'll deploy all the search members we have on standby outside the operational area.","TWN":"好。我會投入所有在作戰區域外待命的搜查隊員。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"두 번 다시 돌아오지 않을 기회야. 며칠이 걸리든 반드시 신병을 확보해야만 해.","JPN":"二度とない機会だ。何日かかろうと、必ず身柄を確保しなければならない。","ENG":"This is an opportunity of a lifetime. We must have her in our custody, no matter how long it takes.","TWN":"這是一個千載難逢的機會。不管花幾天時間，一定要找到她"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 저는 이쯤에서 빠지도록 하죠.","JPN":"では、私はこの辺りで抜けさせてもらいます。","ENG":"Then, I'll see myself out at this point.","TWN":"那我就到此為止吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무대 뒤편의 제 정체가 다른 이들에게 노출되면 곤란하니까요.","JPN":"舞台裏の私の正体が他の者にバレては困りますから。","ENG":"It would prove troublesome if my backstage identity gets exposed to others.","TWN":"如果我在幕後的真實身份被其他人發現，那就麻煩了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"알겠다. 전력 상실은 아쉽지만, 원래부터 그런 조건이었으니까.","JPN":"わかった。戦力が減るのは残念だが、元からそういう条件だったからな。","ENG":"Very well. It's a shame you're leaving, but that was our original terms.","TWN":"明白了。雖然失去你的戰力很可惜，但這就是我們本來的約定。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이번 일로 제가 배신한 게 노출되면 육익은 저를 쫓을 겁니다.","JPN":"今回のことで私の裏切が明るみに出れば、六翼は私を追跡するはずです。","ENG":"If Six Wings find out about my betrayal, they will come after me.","TWN":"如果六翼發現我背叛他們，肯定會追殺報復。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 저는 한동안 평범한 배우로 돌아가겠어요.","JPN":"ですから、私はまたしばらくの間、普通の俳優に戻ります。","ENG":"So, I will go back to being an actress for the time being.","TWN":"所以我暫時會回歸普通演員的生活。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"육익이라는 조직의 특성 상, 이름이 알려진 유명인을 대놓고 해코지하진 않을 테니까요.","JPN":"六翼という組織の性質上、名の知れた者に害を加えることはないでしょうから。","ENG":"Due to the nature of Six Wings, they won't openly harm any well-known celebrities.","TWN":"由於他們組織的特性，六翼不會公然對知名人士下手。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여느 때처럼 관리국 차원의 정보 은폐를 부탁드리죠.","JPN":"いつもどおり、管理局での情報隠ぺいをお願いします。","ENG":"As usual, I ask that the Administration conceal any information about what happened.","TWN":"就像往常一樣，我請求管理局為我隱瞞資訊。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"물론이야. 그건 약속하지.","JPN":"もちろんだ。そこは約束する。","ENG":"Of course. I promise.","TWN":"當然，我保證。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"하지만 역시 묻지 않을 수 없겠군.","JPN":"だが、これだけは聞いておきたい。","ENG":"But I must ask.","TWN":"但還是想問一下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"육익은 관리국이 수년간 추적해 온 테러 집단이었어.","JPN":"六翼は管理局が長い間追跡してきたテロ集団だ。","ENG":"Six Wings is a terrorist organization that the Administration has been after for years.","TWN":"六翼是管理局追蹤多年的恐怖組織。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"그런데 이렇게 쉽게 인적이 드문 곳까지 멤버를 끌어들이다니, 대체 무슨 수를 쓴 거지?","JPN":"なのに、こうも簡単に人けのない場所までおびき出すことができるとは、いったいどんな手を使ったんだ？","ENG":"But how were you able to lure a member to a remote place this easily?","TWN":"你到底是用了什麼辦法，竟然能這麼輕易地把他們的成員騙到這種人跡罕至的地方？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"육익이 탐낼 만한 정보라는 게 대체 뭐였나?","JPN":"六翼が興味を持つほどの情報とは、いったい何だ？","ENG":"What was the information that even Six Wings wanted so badly?","TWN":"六翼會覬覦的資訊到底是什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……잊으셨나 보군요, 리하르트.","JPN":"……忘れたのですか、リヒャルト？","ENG":"...It seems you've forgotten, Richard.","TWN":"……你忘了嗎，理查。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 육익에 대한 첩보를 제공. 그리고 당신은 저의 무대 뒤 활동에 대한 은폐.","JPN":"私は六翼の情報を提供し、あなたは私の舞台裏での活動を隠ぺいしてくれる。","ENG":"Our deal was that I provide intelligence on Six Wings, and you cover up my activities behind the scenes.","TWN":"我提供關於六翼的情報。而你則掩蓋我的幕後活動。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 외 서로에 대한 사소한 비밀은 캐묻지 않기로 했을 텐데요?","JPN":"それ以外の秘密に関してはお互い詮索しない約束だったはずです。","ENG":"Whatever secrets we have, didn't we agree not to ask each other about them?","TWN":"除此之外，我們不是說好了不打聽彼此的小秘密嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"레이디의 비밀을 함부로 파헤치려 하는 건, 신사답지 못한 행동이랍니다.","JPN":"レディーの秘密を暴き出そうだなんて、紳士的とは言えませんよ。","ENG":"It is ungentlemanly behavior trying to delve into a lady's secrets.","TWN":"隨便揭開女士的秘密，可不是紳士的行為喔。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무엇보다 당신도 알고 계실 텐데요.","JPN":"何より、あなたにもわかるはずです。","ENG":"Plus, as you may already know.","TWN":"何況你也知道的吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"부상을 입었다고 해도 퍼스트윙은 결코 만만한 상대가 아닙니다.","JPN":"負傷したとはいえ、ファーストウイングは手強い相手です。","ENG":"Even if she is wounded, Firstwing is no easy opponent.","TWN":"即使受了傷，弗斯特薇也絕不是好對付的對手。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"빈틈을 보이면, 세뇌 능력을 발휘하여 제압이 어려울지도 모르니까요.","JPN":"隙を見せると、洗脳能力を発揮して制圧が難しくなるかもしれません。","ENG":"Show any signs of hesitation, and she'll use her brainwashing abilities to escape your grasp.","TWN":"如果露出一丁點破綻，她可能就會利用洗腦能力，瞬間逃脫。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"대원들에게 정신 교란 재머를 지급하거나, 정신 공격에 내성이 있는 카운터를 투입하는 걸 추천하죠.","JPN":"隊員に精神攪乱ジャマーを支給するか、精神攻撃に耐性を持つカウンターの投入を推奨します。","ENG":"I suggest you provide your men with a mind jammer, or deploy a Counter who is resistant to mental attacks.","TWN":"我建議給隊員們配備精神干擾器，或者派遣對精神攻擊有抗性的制裁者。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요, 오지만디아스 정도의 실력이라면 확실할 겁니다.","JPN":"そうですね、オジマンディアスほどの実力なら安心かと。","ENG":"Yes. Ozymandias should be a perfect match.","TWN":"明白，如果是奧茲曼迪亞斯那樣的實力，肯定沒問題。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"아쉽지만 녀석은 다른 임무에 대응 중이야. 이번 작전엔 참가할 수 없어.","JPN":"残念ながら、あいつは他の任務に対応していて今回の作戦には参加できない。","ENG":"Unfortunately, she's busy with another mission and can't join this one.","TWN":"很遺憾，她正在執行其他任務，無法參加這次行動。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"다른 인원을 선별하겠다.","JPN":"他の人員を選抜しよう。","ENG":"I'll find someone else.","TWN":"我會選擇其他人員。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"알겠습니다.","JPN":"わかりました。","ENG":"Very well.","TWN":"知道了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 이곳 침식지대의 좌표를 보내드리죠.","JPN":"では、この侵食地帯の座標をお送りしましょう。","ENG":"Then, I'll send you the coordinates of this Corrupted Area.","TWN":"那麼，我會把這個侵蝕區域的座標發給你。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"……음?","JPN":"……む？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"잠깐, 스완. 뭔가 착각한 거 아닌가?","JPN":"待て、スワン。何か勘違いしているのではないか？","ENG":"Wait, Swan. I think you're mistaken.","TWN":"等等，史旺。你是不是搞錯了什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜 그러시죠?","JPN":"どうしましたか？","ENG":"What’s wrong?","TWN":"怎麼了？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"자네가 있는 그 좌표는 침식지대가 아닐 텐데?","JPN":"君がいるその座標は、侵食地帯ではないはずだ。","ENG":"The coordinates you gave aren't in the Corrupted Area.","TWN":"你所在的座標應該不是侵蝕地帶吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"거긴 20년 전 대정화 전쟁에서 국제 연합군이 마지막까지 지켜낸 거점 중 하나였어.","JPN":"そこは20年前の大浄化戦争で国際連合軍が最後まで守りぬいた拠点の一つだぞ。","ENG":"That place was one of the last strongholds defended by the Multinational Coalition Force during the Grand Purification War twenty years ago.","TWN":"那裡是20年前大淨化戰爭裡國際聯軍最後守住的據點之一。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"아직도 생생히 떠오르는군.","JPN":"まだはっきりと覚えている。","ENG":"I still remember it vividly.","TWN":"有些事我還歷歷在目呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"우리 부대도 전쟁통에 근처 마을 사람들에게 꽤나 신세를 졌지.","JPN":"うちの部隊も戦争中に近所の村人に世話になったものだ。","ENG":"My unit was also quite indebted to the villagers nearby during the war.","TWN":"我們的部隊在戰爭中也受到了附近村民不少的照顧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHARADE_ADMIN_NULL_NULL","text":{"KOREA":"덕분에 거점을 끝까지 지켜 낼 수 있었고 말이야.","JPN":"おかげで、拠点を最後まで守り通すことができた。","ENG":"Thanks to them, we were able to secure the base until the end.","TWN":"多虧了他們，才能守住據點到最後。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARADE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 근처에 마을이 있다고요……?","JPN":"ではこの近くに村があると……？","ENG":"There was a village nearby...?","TWN":"這附近，有村子嗎……？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 경계 구역\\n<color=#ffd34c>CSE LV.2</color>","JPN":"シャレード～ロータス管理警戒区域\\n<color=#ffd34c>CSE LV.2</color>","ENG":"Charade-Lotus Management Perimeter Zone\\n<color=#ffd34c>CSE Lv. 2</color>","TWN":"查雷德-洛德斯管理警戒區\\n<color=#ffd34c>CSE Lv.2</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 ~ 로터스 관리 개발 구역\\n<color=#ffd34c>CSE LV.0</color>","JPN":"シャレード～ロータス管理開発区域\\n<color=#ffd34c>CSE LV.0</color>","ENG":"Charade-Lotus Management Development Zone\\n<color=#ffd34c>CSE Lv. 0</color>","TWN":"查雷德-洛德斯管理開發區\\n<color=#ffd34c>CSE Lv.0</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"야, 너 거기 안 서!?","JPN":"おい、待て！！","ENG":"Hey! Stop right there!","TWN":"喂，你給我站住？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"이히히, 바보야! 너 같으면 서겠냐?","JPN":"へへへ、バーカ！　待てと言われて待つかよ！","ENG":"Pfft, you idiot! You think I'll stop just because you said so?","TWN":"嘻嘻，笨蛋！有本事就來追我呀？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"얘들아! 뛰지 마! 그러다 넘어지면 어떻게 하려고!","JPN":"みんな、走らないの！　転んでしまうよ！","ENG":"Hey! Don't run! What if you trip and fall?!","TWN":"大家不要跑！摔倒了怎麼辦！"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"사전조사를 했을 때…… 분명 이곳 또한 틀림없이 침식지대였어…….","JPN":"事前調査では……確かにここも侵食地帯だった……","ENG":"When I was doing my research... this place with no doubt was a Corrupted Area...","TWN":"事前調查時……這裡確實也是侵蝕地帶……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 리하르트 말대로야. 작은 마을이지만 사람들이 살고 있군.","JPN":"でもリヒャルトの言ったとおり、小さい村だけど人が住んでいる。","ENG":"But it's just like Richard said. It's a small village where people live.","TWN":"但正如理查所說。雖然是個小村莊，但有人居住。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"저 여자, 아까부터 마을 여기저기를 둘러보고 있는데?","JPN":"あの女の人、さっきから村のあちこちを観察してるんだけど。","ENG":"That woman, why is she looking around our village?","TWN":"那個女生，從剛才開始就在村子裡到處看呢？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"타지에서 오신 분 같은데? 관리국에서 이곳 개발 부지를 조사하러 오신 분 아닐까?","JPN":"他の所から来た人じゃない？　開発のためにここの土地を調べにきた管理局の人かな？","ENG":"She's not from here. What if she's someone from the Administration who came to inspect this place to develop it?","TWN":"看起來像是從外地來的？難道是管理局派來調查這片開發用地的？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"그, 그럼 뭔가 대접해드려야 하는 거 아니야?","JPN":"じゃ、じゃあなんかおもてなしをしないといけないんじゃないの？","ENG":"Th-then, shouldn't we be greeting her?","TWN":"那，我們是不是該招待一下？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마을 설비는 낙후됐지만, 인심은 그다지 흉흉하지 않네.","JPN":"村の設備は老朽化しているけど、住人の雰囲気は穏やかね。","ENG":"The village facilities might be outdated, but the people's spirit here isn't that bad.","TWN":"村裡的設施雖然落後，但人心還算淳樸。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"마치 한적한 옛날 시골 마을 같아. 샤레이드의 빈민가였다면 총부터 들이댔겠지.","JPN":"一昔前の、田舎の村といった感じね。シャレードの貧民街だったら銃口を突きつけられたはず。","ENG":"It feels like an old and quiet village in the country. If I were in the slums of Charade, they would've pointed a gun at me first.","TWN":"就像一個幽靜的古老村落。如果是查雷德的貧民區，早就拔槍要脅了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"리하르트는 이곳 마을이 20년 전부터 여기 있던 것처럼 말했어.","JPN":"リヒャルトはまるで20年前からこの村がここに存在していたかのように話していた。","ENG":"Richard said that this village has been here for twenty years.","TWN":"理查說這個村子好像已經在這裡存在了20年。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"다시 말해, 세피라에 의해서 20년 전에 사라졌던 마을이 다시 생겨난 걸까?","JPN":"つまり、20年前に消滅したはずの村がセフィラによって復活した？","ENG":"In other words, Sephira caused a village that had vanished twenty years ago to reappear?","TWN":"換句話說，是因為塞菲拉，20年前消失的村莊又重新出現了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"강력한 정보왜곡을 동반한 현실개변…….","JPN":"強力な情報の歪曲を伴う現実改変……","ENG":"A change in reality accompanied by a strong distortion in information...","TWN":"伴隨著強烈的資訊扭曲，現實發生了改變……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"예상대로야. 세계를 만드는 법칙이라는 건 어쩌면 정말로…….","JPN":"予想どおりね。世界を作る法則というのは、もしかすると本当に……","ENG":"Just as I expected. The law of creating a world is perhaps...","TWN":"果然不出所料。所謂的創造世界的法則，或許真的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 어째서지?","JPN":"でもどうして？","ENG":"But why?","TWN":"但為什麼呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이런 작은 마을을 하나 되돌리는 게 무슨 의미가 있다는 거야?","JPN":"こんな小さな村一つを復活させることに、何の意味がある？","ENG":"What meaning does restoring a small village have?","TWN":"讓這樣一個小村莊恢復原狀有什麼意義呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"……음?","JPN":"……うん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"저, 저기……. 안녕하세요, 언니……?","JPN":"あ、あの……こんにちは。","ENG":"U-um... Hello, miss...","TWN":"那，那個……你好，姊姊……？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜 그러지? 나한테 무슨 볼일이라도 있니?","JPN":"どうしたの？　私に何か用があるのかしら？","ENG":"What is it? Is there something you want to say to me?","TWN":"怎麼了？你找我有什麼事嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"저, 한스 아저씨가 마을에 오신 손님께 잘 보여야 한다고 해서요.","JPN":"えっと、ハンスおじさんが……村に来てくれたお客さんには親切にしなさいって。","ENG":"Um, Uncle Hans said that I should be polite to the guest who came to our village.","TWN":"那個，漢斯大叔說村裡來了客人，要好好招待。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"우리 집에서 재배한 사과로 만든 애플파이에요. 맛 좀 보실래요?","JPN":"これ、うちで育てたリンゴで作ったアップルパイです。一口どうですか？","ENG":"This is an apple pie made with homegrown apples. Would you like a taste?","TWN":"這是用我們家種的蘋果做的蘋果派，要嚐嚐看嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 고맙네. 잘 먹을게.","JPN":"ふふ、ありがとう。じゃあいただくね。","ENG":"Haha, thank you. It looks delicious.","TWN":"哈哈，謝謝。我會好好享用的。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"저…… 언니는 도시에서 오셨나 봐요.","JPN":"あの……お姉さんは、都会から来たんですよね。","ENG":"Um... did you come from the city?","TWN":"那個……姊姊是從城市來的吧。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"맞아. 이 근방을 여행하다가 들렸거든. 설마 이런 곳에 마을이 있을 줄은 몰랐지만.","JPN":"ええ。近くを旅していたの。まさかこんなところに村があるとは思わなかった。","ENG":"Yes. I stopped by while traveling around here. I didn't even know a village existed here.","TWN":"沒錯。我在附近旅行時順便過來看看，沒想到這裡竟然有個村子。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"아아, 그렇구나.","JPN":"へえ、そうなんだ。","ENG":"Oh, I see.","TWN":"啊……這樣啊。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"그, 그럼 언니는 어디에서 왔어요? 챔버? 샤레이드? 아니면, 그라운드 원……?","JPN":"じゃ、じゃあお姉さんはどこから来ましたか？　チェンバー？　シャレード？　それとも、グラウンド・ワン……？","ENG":"Th-then, which city did you come from? Chamber? Charade? Or Ground One...?","TWN":"那，姊姊是從哪裡來的？是從強巴？還是從查雷德？或者是G1……？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"도시는 어떤 곳인가요? 저, 사실 도시에 가고 싶거든요.","JPN":"都会ってどんなところですか？　実は私も都会に行きたくて。","ENG":"What's it like in the city? I... actually want to go there once.","TWN":"城市是個什麼樣的地方？其實，我很想去城市看看。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"무, 물론, 당장은 돈도 없고 부모님도 반대하셔서 힘들지만요…….","JPN":"も、もちろん今はお金もないし両親も反対しているから無理だけど……","ENG":"O-of course, I can't right now because I'm poor and my parents are against it...","TWN":"當，當然，現在既沒錢又有父母反對，所以很難……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"나는 이 마을 분위기도 한적하니 나쁘지 않은 것 같은데?","JPN":"私はこの村ものどかでいいところだと思うけど。","ENG":"I think this village is nice and quiet.","TWN":"我覺得這個村子的氣氛也很寧靜，不錯啊？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"왜 도시에 가고 싶은 지 물어봐도 될까?","JPN":"どうして都会に行きたいの？　聞いてもいい？","ENG":"May I ask why you wish to live in a city?","TWN":"能問問你為什麼想去城市嗎？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"우웅. 물론 여기도 나쁘지 않지만 전 하고 싶은 게 많거든요. 먹고 싶은 것도 많고요.","JPN":"うーん……ここも悪くはないけど、私やりたいことがたくさんあるんです。食べたいものもたくさんあって。","ENG":"Um, it's not that I don't like this place, but there's a lot that I want to do. And a lot of things I want to eat.","TWN":"嗯嗯。當然這裡也不錯，但我有很多想做的事情，還有很多想吃的東西。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"그리고 무엇보다도…….","JPN":"なにより……","ENG":"But above all else...","TWN":"而且，最重要的是……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"만나고 싶은 사람이 있어요.","JPN":"会いたい人がいるんです。","ENG":"there's someone I want to meet.","TWN":"我有個想見的人。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"물론, 그 사람은 저를 어떻게 생각할 지 모르겠지만…….","JPN":"その人は、私のことをどう思っているか、わからないけど……","ENG":"I-I don't even know what that person will think of me, though...","TWN":"當然，可能不知道那個人會怎麼看待我……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"그래도 전 꼭 만나고 싶어요.","JPN":"それでも絶対会いたいんです。","ENG":"I still want to meet this person.","TWN":"即便如此，我還是很想去見一見。"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WOMAN_SWANSONG_NPC_NULL","text":{"KOREA":"만나고 싶은 사람?","JPN":"会いたい人？","ENG":"Someone you want to meet?","TWN":"你想見的人？"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"네, 그 사람은…….","JPN":"はい。あの人は……","ENG":"Yes, and that person is...","TWN":"是的，那個人……"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};